C1.current_terraform:
resource "aws_cloudwatch_log_group" "app_logs_prod" {
  name = "/aws/application/app-logs-prod"
  # retention_in_days not set — logs retained indefinitely

  tags = {
    Name        = "app-logs-prod"
    Environment = "production"
  }
}

C2.current_terraform:
resource "aws_cloudwatch_log_group" "high_volume_logs" {
  name              = "/aws/application/high-volume-logs"
  retention_in_days = 90

  tags = {
    Name        = "high-volume-logs"
    Environment = "production"
  }
}
# No S3 export subscription configured

C4.current_terraform:
resource "aws_ebs_volume" "ghost_volume_0a1b2c3d" {
  availability_zone = "us-east-1a"
  size              = 100
  type              = "gp3"
  encrypted         = false

  tags = {
    Name = "ghost-volume-0a1b2c3d"
  }
}

C5.current_terraform:
resource "aws_s3_bucket" "company_data_archive_prod" {
  bucket = "company-data-archive-prod"

  tags = {
    Name        = "company-data-archive-prod"
    Environment = "production"
  }
}
# No lifecycle configuration — all objects stored in S3 Standard
